// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Create a context with timeout for DoS protection
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	vm := goja.New()

	// Inject the entire order object as a global variable
	vm.Set("order", order)

	// Also inject individual order fields as global variables for backward compatibility
	for key, value := range order {
		vm.Set(key, value)
	}

	// Create a channel to handle the result
	resultChan := make(chan goja.Value, 1)
	errChan := make(chan error, 1)

	// Execute the script in a goroutine with timeout protection
	go func() {
		// Set up a timer to interrupt the VM if it takes too long
		timer := time.AfterFunc(5*time.Second, func() {
			vm.Interrupt("execution timeout")
		})
		defer timer.Stop()

		result, err := vm.RunString(script)
		if err != nil {
			errChan <- err
			return
		}
		resultChan <- result
	}()

	// Wait for either result, error, or timeout
	select {
	case err := <-errChan:
		return 0.0, fmt.Errorf("script execution error: %w", err)
	case result := <-resultChan:
		// Handle nil or undefined result
		if result == nil || goja.IsUndefined(result) {
			return 0.0, fmt.Errorf("script must return a number, got undefined")
		}

		// Convert result to float64
		exported := result.Export()

		var discount float64
		switch v := exported.(type) {
		case float64:
			discount = v
		case int:
			discount = float64(v)
		case int32:
			discount = float64(v)
		case int64:
			discount = float64(v)
		case float32:
			discount = float64(v)
		default:
			return 0.0, fmt.Errorf("script must return a number, got %T", exported)
		}

		return discount, nil
	case <-ctx.Done():
		return 0.0, fmt.Errorf("script execution timeout: exceeded 5 second limit")
	}
}

