func toFloat64(result goja.Value) (float64, error) {
	exported := result.Export()

	// Direct float64 conversion
	if discount, ok := exported.(float64); ok {
		return discount, nil
	}

	// Try to convert from other numeric types
	switch v := exported.(type) {
	case int:
		return float64(v), nil
	case int32:
		return float64(v), nil
	case int64:
		return float64(v), nil
	case float32:
		return float64(v), nil
	case string:
