		var f float64
		_, err := fmt.Sscanf(v, "%f", &f)
		if err != nil {
			return 0.0, fmt.Errorf("script must return a number, got string: %s", v)
		}
		return f, nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}
